trait PrattParser { fn parse(&self, tokens: Vec<&str>) -> Result<i32, &'static str>; }

struct Add;
impl PrattParser for Add {
    fn parse(&self, tokens: Vec<&str>) -> Result<i32, &'static str> {
        let mut acc = 0;
        for token in tokens.iter() {
            if *token == "+" { continue; }
            match token.parse::<i32>() {
                Ok(num) => acc += num,
                Err(_) => return Err("parse error")
            }
        }
        Ok(acc)
    }
}

fn main() {
    let parser = Add;
    let result = parser.parse(vec!["1", "+", "2"]); // should be 3 but causes panic
    println!("{:?}", result);
}

